async (params, browser) => {
  // Open housing search
  await browser.open(`https://${params.city}.craigslist.org/search/apa?query=${params.query}`)

  // Wait for content
  await browser.waitForSelector('.cl-search-result, .result-row, .cl-static-search-result, body', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const results = []; document.querySelectorAll('.cl-search-result, .result-row, .cl-static-search-result').forEach((el,i) => { if(i>=15) return; const titleEl = el.querySelector('a.posting-title, a.result-title, a.cl-app-anchor'); const priceEl = el.querySelector('.priceinfo, .result-price'); const meta = el.querySelector('.housing, .meta, .result-meta')?.textContent?.trim()||''; results.push({ title: titleEl?titleEl.textContent.trim():'', url: titleEl?titleEl.href:'', price: priceEl?priceEl.textContent.trim():'', details: meta }); }); return { city: '' + params.city + '', query: '' + params.query + '', result_count: results.length, results }`)

  return page_data
}
